import React, { useState, useEffect } from 'react';
import axios from 'axios';

function ClientDashboard() {
  const [projects, setProjects] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const fetchAllProjects = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setProjects(res.data);
      setLoading(false);
    } catch (err) {
      setError("❌ Failed to sync data with the server.");
      setLoading(false);
    }
  };

  useEffect(() => { fetchAllProjects(); }, []);

  const handleRevision = async (id) => {
    const msg = document.getElementById(`rev-${id}`).value;
    if (!msg.trim()) return alert("Please describe the changes!");
    try {
      await axios.put(`http://localhost:5000/api/update-status/${id}`, { revisionsRequested: msg });
      alert("✅ Request Sent!");
      document.getElementById(`rev-${id}`).value = "";
      fetchAllProjects();
    } catch (err) { alert("Failed to send."); }
  };

  // --- Professional Payment Status Logic ---
  const renderPaymentStatus = (proj) => {
    const total = Number(proj.totalBudget) || 0;
    const paid = Number(proj.advancePaid) || 0;
    const balance = total - paid;

    if (total > 0 && balance <= 0) {
      return (
        <div className="payment-success-card">
          <div className="icon-circle">✅</div>
          <div className="msg-box">
            <span className="main-text">DIRECT FULL FEES PAID</span>
            <span className="sub-text">Total Received: ₹{paid}</span>
          </div>
        </div>
      );
    }

    return (
      <div className="payment-pending-box">
        <div className="pay-row">
            <span>Total Budget:</span> <b>₹{total}</b>
        </div>
        <div className="pay-row text-success">
            <span>Advance Paid:</span> <b>₹{paid}</b>
        </div>
        <div className="balance-row mt-2 pt-2 border-top">
            <span className="fw-bold">Remaining Balance:</span>
            <span className="text-danger fs-5 fw-extrabold">₹{balance}</span>
        </div>
      </div>
    );
  };

  return (
    <div className="client-dashboard">
      <style>{`
        @import url('https://fonts.googleapis.com');
        
        .client-dashboard { 
          background: #fdfdfd; 
          min-height: 100vh; 
          padding: 50px 20px; 
          font-family: 'Plus Jakarta Sans', sans-serif;
          color: #1a202c;
        }

        .header-section { text-align: center; margin-bottom: 50px; }
        .header-section h2 { font-weight: 800; font-size: 2.5rem; letter-spacing: -1.5px; margin-bottom: 10px; color: #111; }
        .header-section p { color: #718096; font-size: 1.1rem; }

        .project-card { 
          background: white; 
          border-radius: 24px; 
          box-shadow: 0 10px 30px rgba(0,0,0,0.04); 
          border: 1px solid #f0f0f0; 
          margin-bottom: 30px; 
          overflow: hidden;
          transition: 0.3s;
        }
        .project-card:hover { transform: translateY(-5px); box-shadow: 0 20px 40px rgba(0,0,0,0.08); }

        .card-header { 
          background: #111; 
          padding: 20px 30px; 
          display: flex; 
          justify-content: space-between; 
          align-items: center; 
        }
        .card-header h5 { color: #ffcc00; font-weight: 700; margin: 0; text-transform: lowercase; font-size: 1.1rem; }
        .status-badge { 
          background: #ffcc00; 
          color: #000; 
          font-weight: 800; 
          padding: 6px 15px; 
          border-radius: 12px; 
          font-size: 0.75rem; 
          text-transform: uppercase;
        }

        .card-body { padding: 35px; }
        .section-title { font-size: 0.7rem; font-weight: 800; color: #a0aec0; text-transform: uppercase; letter-spacing: 1.5px; margin-bottom: 20px; display: block; }

        /* Progress Styles */
        .progress-wrap { background: #f7fafc; border-radius: 20px; height: 12px; overflow: hidden; margin-bottom: 15px; }
        .progress-bar { background: linear-gradient(90deg, #3182ce 0%, #63b3ed 100%); height: 100%; border-radius: 20px; }
        .progress-label { font-weight: 800; color: #3182ce; font-size: 1.5rem; }

        /* Payment UI */
        .payment-success-card { 
          background: #f0fff4; 
          border: 1px solid #c6f6d5; 
          padding: 15px; 
          border-radius: 16px; 
          display: flex; 
          align-items: center; 
          gap: 15px;
        }
        .icon-circle { background: #2f855a; color: white; width: 35px; height: 35px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 1rem; }
        .main-text { display: block; font-weight: 800; color: #22543d; font-size: 0.85rem; }
        .sub-text { font-size: 0.75rem; color: #2f855a; }
        .pay-row { display: flex; justify-content: space-between; font-size: 0.9rem; margin-bottom: 8px; }

        /* Revision Input */
        .rev-input { 
          border: 2px solid #edf2f7; 
          border-radius: 12px; 
          padding: 12px; 
          font-size: 0.9rem; 
          width: 100%; 
          transition: 0.2s; 
          outline: none;
        }
        .rev-input:focus { border-color: #3182ce; }
        .send-btn { 
          background: #111; 
          color: white; 
          border: none; 
          border-radius: 12px; 
          padding: 12px 25px; 
          font-weight: 700; 
          cursor: pointer; 
          transition: 0.2s;
        }
        .send-btn:hover { background: #333; }

        @media (max-width: 768px) { .col-md-4 { margin-bottom: 30px; border: none !important; } }
      `}</style>

      <div className="header-section">
        <h2>Live Project Tracker</h2>
        <p>Real-time updates on your development journey.</p>
      </div>

      <div className="container shadow-none p-0">
        {projects.map((proj) => (
          <div className="project-card" key={proj._id}>
            <div className="card-header">
              <h5>{proj.fullName} — {proj.serviceType}</h5>
              <span className="status-badge">{proj.status}</span>
            </div>
            <div className="card-body">
              <div className="row">
                {/* 1. Work Progress */}
                <div className="col-md-4 border-end pe-4">
                  <span className="section-title">Development Progress</span>
                  <div className="progress-label mb-2">{proj.progress}%</div>
                  <div className="progress-wrap">
                    <div className="progress-bar" style={{ width: `${proj.progress}%` }}></div>
                  </div>
                  <small className="text-muted">Estimated completion based on features.</small>
                </div>

                {/* 2. Payment Summary */}
                <div className="col-md-4 px-4 border-end">
                  <span className="section-title">Financial Overview</span>
                  {renderPaymentStatus(proj)}
                </div>

                {/* 3. Revision Requests */}
                <div className="col-md-4 ps-4">
                  <span className="section-title">Quick Action / Revisions</span>
                  <div className="d-flex flex-column gap-3">
                    <input id={`rev-${proj._id}`} className="rev-input" placeholder="Need any changes? Type here..." />
                    <button className="send-btn" onClick={() => handleRevision(proj._id)}>Submit Request</button>
                  </div>
                  {proj.revisionsRequested && (
                    <div className="mt-3 p-2 bg-light rounded small border">
                      <b>Current Revision:</b> {proj.revisionsRequested}
                    </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default ClientDashboard;
